// >>> A MODIFIER : colle ta cle Google Places ici <<<
const apiKey = "COLLE_TA_CLE_GOOGLE_ICI";

// Departements a prospecter (rotation : 1 different chaque jour). Edite la liste librement.
const departements = ["Dordogne", "Lot", "Gard", "Vaucluse", "Var", "Alpes-Maritimes", "Hérault", "Pyrénées-Orientales", "Pyrénées-Atlantiques", "Landes", "Gironde", "Charente-Maritime", "Vendée", "Morbihan", "Finistère", "Côtes-d'Armor", "Calvados", "Manche", "Savoie", "Haute-Savoie", "Isère", "Hautes-Alpes", "Ardèche", "Drôme", "Lozère", "Aveyron", "Corse-du-Sud", "Haute-Corse", "Haute-Loire", "Cantal"];

const start = Date.UTC(new Date().getUTCFullYear(), 0, 0);
const dayOfYear = Math.floor((Date.now() - start) / 86400000);
const d = departements[dayOfYear % departements.length];

// 8 requetes pour couvrir le marche (Places renvoie ~20 resultats par requete)
const modeles = [
  "gîte {d}",
  "chambre d'hôtes {d}",
  "maison d'hôtes {d}",
  "gîte de charme {d}",
  "gîte rural {d}",
  "location vacances {d}",
  "bed and breakfast {d}",
  "hébergement touristique {d}",
];
const out = [];
for (const m of modeles) {
  out.push({ json: { query: m.replace("{d}", d), departement: d, apiKey } });
}
return out;

// Aplatit les resultats, exclut gites d'etape + annuaires, deduplique par domaine
const departement = $('1. Préparer les recherches').first().json.departement;
const DIRS = ["booking.com","airbnb.com","airbnb.fr","gites-de-france.com",
  "cybevasion.fr","abritel.fr","vrbo.com","tripadvisor.fr","tripadvisor.com",
  "leboncoin.fr","homeexchange.fr","homeaway.fr"];
const seen = new Set();
const out = [];
for (const item of $input.all()) {
  const places = item.json.places || [];
  for (const p of places) {
    const site = p.websiteUri;
    const nom = (p.displayName && p.displayName.text) || "";
    // 1. Anti-etape : on saute les gites d'etape (offre Kordia pas encore prete)
    const nomLow = nom.toLowerCase();
    if (nomLow.includes("étape") || nomLow.includes("etape")) continue;
    // 2. Doit avoir un site web
    if (!site) continue;
    // 3. Dedup par domaine + exclure les annuaires (Booking, Airbnb...)
    const domain = site.toLowerCase().replace(/^https?:\/\//, "").replace(/^www\./, "").split("/")[0];
    if (!domain || seen.has(domain)) continue;
    if (DIRS.some((dir) => domain.endsWith(dir))) continue;
    seen.add(domain);
    out.push({ json: {
      departement,
      nom,
      adresse: p.formattedAddress || "",
      telephone: p.nationalPhoneNumber || "",
      site,
    }});
  }
}
return out;

// Visite chaque site et extrait le premier email de contact trouve
const EMAIL_RE = /[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}/g;
const BLOCK = ["example.com","exemple","domaine.com","votre","utilisateur","monemail",
  "test@","wixpress","sentry","godaddy","jimdo","squarespace",
  ".png",".jpg",".jpeg",".gif",".webp",".svg","@2x",
  "booking.com","airbnb.com","airbnb.fr","gites-de-france.com","cybevasion.fr",
  "abritel.fr","vrbo.com","tripadvisor"];
const seenEmails = new Set();
const out = [];
for (const item of $input.all()) {
  const d = item.json;
  let html = "";
  try {
    const res = await this.helpers.httpRequest({
      url: d.site, method: "GET", timeout: 12000,
      headers: { "User-Agent": "Mozilla/5.0 (KordiaProspection)" },
    });
    html = typeof res === "string" ? res : JSON.stringify(res);
  } catch (e) { html = ""; }
  const found = (html.match(EMAIL_RE) || [])
    .map((e) => e.toLowerCase().replace(/^(%[0-9a-f]{2})+/i, "").replace(/\.$/, ""))
    .filter((e) => !BLOCK.some((b) => e.includes(b)));
  const email = found[0] || "";
  if (email && seenEmails.has(email)) continue;
  if (email) seenEmails.add(email);
  out.push({ json: {
    departement: d.departement, nom: d.nom, email,
    telephone: d.telephone, site: d.site, adresse: d.adresse,
    date_ajout: new Date().toISOString().slice(0, 10),
  }});
  await new Promise((r) => setTimeout(r, 800));
}
return out;

// Resume du scrape : 1 ligne pour le Journal (compteur)
const items = $input.all();
const departement = $('1. Préparer les recherches').first().json.departement;
return [{ json: {
  departement,
  date: new Date().toISOString().slice(0, 16).replace("T", " "),
  nb_leads: items.length,
}}];
